public String makePalindrome(String string) {
    if (string == null || string.isEmpty()) {
        return string;
    }

    // Find the longest palindromic suffix
    int n = string.length();
    for (int i = 0; i < n; i++) {
        // Check if substring from i to end is a palindrome
        if (isPalindrome(string.substring(i))) {
            // Found longest palindromic suffix starting at i
            String prefix = string.substring(0, i);
            String reversePrefix = new StringBuilder(prefix).reverse().toString();
            return string + reversePrefix;
        }
    }

    // Fallback (shouldn't reach here since single char is always palindrome)
    return string;
}

