class Solution {
    /**
    For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largestDivisor(15)
    5
     */
    public int largestDivisor(int n) {
        // Handle edge cases
        if (n <= 2) {
            return 1;
        }

        // If n is even, largest proper divisor is n/2
        if (n % 2 == 0) {
            return n / 2;
        }

        // For odd numbers, find the smallest prime factor
        for (int i = 3; i * i <= n; i += 2) {
            if (n % i == 0) {
                return n / i;
            }
        }

        // If no divisor found, n is prime, so largest proper divisor is 1
        return 1;
    }
}

