     */
    public List<Integer> removeDuplicates(List<Integer> numbers) {
        // Count frequency of each element
        Map<Integer, Long> frequencyMap = numbers.stream()
                .collect(Collectors.groupingBy(
                    n -> n,
                    Collectors.counting()
