public boolean isPrime(int n) {
    // Handle edge cases
    if (n <= 1) {
        return false;
    }
    if (n == 2) {
        return true;
    }
    // Even numbers > 2 are not prime
    if (n % 2 == 0) {
        return false;
    }

    // Check odd divisors from 3 to sqrt(n)
    for (int i = 3; i * i <= n; i += 2) {
        if (n % i == 0) {
            return false;
        }
    }

    return true;
}

public double findZero(List<Double> xs) {
    // If constant term is zero, then x=0 is a root
    if (Math.abs(xs.get(0)) < 1e-12) {
