    for (int i = 1; i <= 10; i++) {
        double val = poly(xs, i);
        if (Math.abs(val) < 1e-9) {
            return i;
        }
        val = poly(xs, -i);
        if (Math.abs(val) < 1e-9) {
            return -i;
        }
