    // Find leading coefficient (largest non-zero)
    double leadingCoeff = 0;
    for (int i = xs.size() - 1; i >= 0; i--) {
        if (Math.abs(xs.get(i)) > 1e-12) {
            leadingCoeff = xs.get(i);
            break;
        }
    }

    // Determine search range based on leading coefficient
    double left = -100.0;
    double right = 100.0;

    // Expand range if needed to ensure sign change
    double fLeft = poly(xs, left);
    double fRight = poly(xs, right);

    // Try expanding range until we get sign change
    int attempts = 0;
    while (fLeft * fRight > 0 && attempts < 20) {
        left *= 2;
        right *= 2;
        fLeft = poly(xs, left);
        fRight = poly(xs, right);
        attempts++;
    }

    // If still no sign change, try narrower range around 0
    if (fLeft * fRight > 0) {
        left = -10;
        right = 10;
        fLeft = poly(xs, left);
        fRight = poly(xs, right);
        attempts = 0;
        while (fLeft * fRight > 0 && attempts < 10) {
            left *= 0.5;
            right *= 0.5;
            fLeft = poly(xs, left);
            fRight = poly(xs, right);
            attempts++;
        }
        if (fLeft * fRight > 0) {
            // Fallback: try derivative-based approach or just return 0
            return 0.0;
        }
    }

    // Bisection method to find root
    for (int iter = 0; iter < 100; iter++) {
        double mid = (left + right) / 2;
        double fMid = poly(xs, mid);

        if (Math.abs(fMid) < 1e-12) {
            return mid;
        }

        if (fLeft * fMid <= 0) {
            right = mid;
            fRight = fMid;
        } else {
            left = mid;
            fLeft = fMid;
        }
    }

    // Return midpoint as final approximation
    return (left + right) / 2;
}

public List<Integer> sortThird(List<Integer> l) {
    List<Integer> result = new ArrayList<>(l);

    // Extract elements at indices divisible by 3
    List<Integer> thirdElements = new ArrayList<>();
    for (int i = 0; i < l.size(); i += 3) {
        thirdElements.add(l.get(i));
    }

    // Sort the extracted elements
    Collections.sort(thirdElements);

    // Put sorted elements back at their positions
    int sortedIndex = 0;
    for (int i = 0; i < l.size(); i += 3) {
        result.set(i, thirdElements.get(sortedIndex++));
    }

    return result;
}

